import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useParams, useNavigate } from 'react-router-dom';
import { CssBaseline } from '@mui/material';
import { ThemeProvider } from '@mui/material/styles';
import { AuthProvider, useAuth } from './contexts/AuthContext.tsx';
import theme from './styles/theme.ts';

// Layout Components
import Navbar from './components/Navbar.tsx';
import Sidebar from './components/Sidebar.tsx';

// Public Pages
import Home from './pages/Home.tsx';
import Login from './pages/Login.tsx';
import Register from './pages/Register.tsx';
import JobListings from './pages/JobListings.tsx';
import JobDetails from './pages/JobDetails.tsx';

// Applicant Pages
import ApplicantDashboard from './components/ApplicantDashboard.tsx';
import ApplicationForm from './pages/JobApplicationForm.tsx';
import InterviewRoom from './pages/InterviewRoom.tsx';

// Admin Pages
import AdminDashboard from './components/admin/AdminDashboard.tsx';
import JobsManagement from './components/admin/JobsManagement.tsx';
import CandidatesList from './components/admin/CandidatesList.tsx';
import InterviewResults from './components/admin/InterviewResults.tsx';
import AdminSettings from './components/admin/AdminSettings.tsx';

interface ProtectedRouteProps {
  children: React.ReactNode;
  roles?: string[];
}

const ProtectedRoute: React.FC<ProtectedRouteProps> = ({ children, roles }) => {
  const { user, loading } = useAuth();

  if (loading) {
    return <div>Loading...</div>;
  }

  if (!user) {
    return <Navigate to="/login" />;
  }

  if (roles && !roles.includes(user.role)) {
    return <Navigate to="/" />;
  }

  return <>{children}</>;
};

const InterviewResultsWrapper: React.FC = () => {
  const { candidateId } = useParams<{ candidateId: string }>();
  return <InterviewResults candidateId={Number(candidateId)} />;
};

const AppRoutes: React.FC = () => {
  const navigate = useNavigate();

  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar />
      <div className="flex">
        <Sidebar />
        <main className="flex-1 p-8">
          <Routes>
            {/* Public Routes */}
            <Route path="/" element={<Home />} />
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Register />} />
            <Route path="/jobs" element={<JobListings />} />
            <Route path="/jobs/:id" element={<JobDetails />} />

            {/* Applicant Routes */}
            <Route
              path="/applicant/dashboard"
              element={
                <ProtectedRoute roles={['APPLICANT']}>
                  <ApplicantDashboard />
                </ProtectedRoute>
              }
            />
            <Route
              path="/applicant/apply/:jobId"
              element={
                <ProtectedRoute roles={['APPLICANT']}>
                  <ApplicationForm />
                </ProtectedRoute>
              }
            />
            <Route
              path="/applicant/interview/:applicationId"
              element={
                <ProtectedRoute roles={['APPLICANT']}>
                  <InterviewRoom />
                </ProtectedRoute>
              }
            />

            {/* Admin Routes */}
            <Route
              path="/admin/dashboard"
              element={
                <ProtectedRoute roles={['ADMIN', 'RECRUITER']}>
                  <AdminDashboard />
                </ProtectedRoute>
              }
            />
            <Route
              path="/admin/jobs"
              element={
                <ProtectedRoute roles={['ADMIN', 'RECRUITER']}>
                  <JobsManagement />
                </ProtectedRoute>
              }
            />
            <Route
              path="/admin/candidates"
              element={
                <ProtectedRoute roles={['ADMIN', 'RECRUITER']}>
                  <CandidatesList onSelectCandidate={(id) => navigate(`/admin/interview/${id}`)} />
                </ProtectedRoute>
              }
            />
            <Route
              path="/admin/interview/:candidateId"
              element={
                <ProtectedRoute roles={['ADMIN', 'RECRUITER']}>
                  <InterviewResultsWrapper />
                </ProtectedRoute>
              }
            />
            <Route
              path="/admin/settings"
              element={
                <ProtectedRoute roles={['ADMIN']}>
                  <AdminSettings />
                </ProtectedRoute>
              }
            />

            {/* 404 Route */}
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <AuthProvider>
        <Router>
          <AppRoutes />
        </Router>
      </AuthProvider>
    </ThemeProvider>
  );
};

export default App;
